type ServerConfig struct {
    Host           string
    Port           int
    MaxConnections int
    Timeout        int
    Logging        LogConfig
    Metrics        MetricsConfig
    Auth           AuthConfig
}

type LogConfig struct {
    Enabled bool
    Level   string
}

