    Enabled  bool
    Provider string
}

func configureServer(config ServerConfig) *Server {
    // Well-organized configuration
    return nil
}

// GOOD: Builder pattern for complex objects
type ServerConfigBuilder struct {
    config ServerConfig
}

func NewServerConfigBuilder() *ServerConfigBuilder {
    return &ServerConfigBuilder{
        config: ServerConfig{
            Host: "localhost",
            Port: 8080,
        },
    }
}

func (b *ServerConfigBuilder) WithHost(host string) *ServerConfigBuilder {
    b.config.Host = host
    return b
}

func (b *ServerConfigBuilder) WithPort(port int) *ServerConfigBuilder {
    b.config.Port = port
    return b
}

func (b *ServerConfigBuilder) WithLogging(enabled bool, level string) *ServerConfigBuilder {
    b.config.Logging = LogConfig{Enabled: enabled, Level: level}
    return b
}

func (b *ServerConfigBuilder) Build() ServerConfig {
    return b.config
}

// Usage example:
// config := NewServerConfigBuilder().
//     WithHost("0.0.0.0").
//     WithPort(9000).
//     WithLogging(true, "info").
//     Build()
// server := configureServer(config)

// GOOD: Functional options pattern
type ServerOption func(*ServerConfig)

func WithHostOption(host string) ServerOption {
    return func(c *ServerConfig) {
        c.Host = host
    }
}

func WithPortOption(port int) ServerOption {
    return func(c *ServerConfig) {
        c.Port = port
    }
}

func NewServer(options ...ServerOption) *Server {
    config := &ServerConfig{
        Host: "localhost",
        Port: 8080,
    }

    for _, option := range options {
        option(config)
    }

    return configureServer(*config)
}

